142	#[must_use]
143	pub fn metadata_for_model(model: &str) -> Option<ProviderMetadata> {
144	    let canonical = resolve_model_alias(model);
145	    if canonical.starts_with("claude") {
146	        return Some(ProviderMetadata {
147	            provider: ProviderKind::Anthropic,
148	            auth_env: "ANTHROPIC_API_KEY",
149	            base_url_env: "ANTHROPIC_BASE_URL",
150	            default_base_url: anthropic::DEFAULT_BASE_URL,
151	        });
152	    }
153	    if canonical.starts_with("grok") {
154	        return Some(ProviderMetadata {
155	            provider: ProviderKind::Xai,
156	            auth_env: "XAI_API_KEY",
157	            base_url_env: "XAI_BASE_URL",
158	            default_base_url: openai_compat::DEFAULT_XAI_BASE_URL,
159	        });
160	    }
161	    None
162	}
163	
164	#[must_use]
165	pub fn detect_provider_kind(model: &str) -> ProviderKind {
166	    if let Some(metadata) = metadata_for_model(model) {
167	        return metadata.provider;
168	    }
169	    if anthropic::has_auth_from_env_or_saved().unwrap_or(false) {
170	        return ProviderKind::Anthropic;
171	    }
172	    if openai_compat::has_api_key("OPENAI_API_KEY") {
173	        return ProviderKind::OpenAi;
174	    }
175	    if openai_compat::has_api_key("XAI_API_KEY") {
176	        return ProviderKind::Xai;
177	    }
178	    ProviderKind::Anthropic
179	}
