39	impl AuthSource {
40	    pub fn from_env() -> Result<Self, ApiError> {
41	        let api_key = read_env_non_empty("ANTHROPIC_API_KEY")?;
42	        let auth_token = read_env_non_empty("ANTHROPIC_AUTH_TOKEN")?;
43	        match (api_key, auth_token) {
44	            (Some(api_key), Some(bearer_token)) => Ok(Self::ApiKeyAndBearer {
45	                api_key,
46	                bearer_token,
47	            }),
48	            (Some(api_key), None) => Ok(Self::ApiKey(api_key)),
49	            (None, Some(bearer_token)) => Ok(Self::BearerToken(bearer_token)),
50	            (None, None) => Err(ApiError::missing_credentials(
51	                "Anthropic",
52	                &["ANTHROPIC_AUTH_TOKEN", "ANTHROPIC_API_KEY"],
53	            )),
