59	        match self {
60	            Self::ApiKey(api_key) | Self::ApiKeyAndBearer { api_key, .. } => Some(api_key),
61	            Self::None | Self::BearerToken(_) => None,
62	        }
63	    }
64	
65	    #[must_use]
66	    pub fn bearer_token(&self) -> Option<&str> {
67	        match self {
68	            Self::BearerToken(token)
69	            | Self::ApiKeyAndBearer {
70	                bearer_token: token,
71	                ..
72	            } => Some(token),
73	            Self::None | Self::ApiKey(_) => None,
74	        }
75	    }
