86	    pub fn apply(&self, mut request_builder: reqwest::RequestBuilder) -> reqwest::RequestBuilder {
87	        if let Some(api_key) = self.api_key() {
88	            request_builder = request_builder.header("x-api-key", api_key);
89	        }
90	        if let Some(token) = self.bearer_token() {
91	            request_builder = request_builder.bearer_auth(token);
92	        }
93	        request_builder
94	    }
