62	impl Display for ApiError {
63	    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
64	        match self {
65	            Self::MissingCredentials { provider, env_vars } => write!(
66	                f,
67	                "missing {provider} credentials; export {} before calling the {provider} API",
68	                env_vars.join(" or ")
69	            ),
70	            Self::ExpiredOAuthToken => {
71	                write!(
72	                    f,
73	                    "saved OAuth token is expired and no refresh token is available"
74	                )
75	            }
76	            Self::Auth(message) => write!(f, "auth error: {message}"),
77	            Self::InvalidApiKeyEnv(error) => {
78	                write!(f, "failed to read credential environment variable: {error}")
79	            }
80	            Self::Http(error) => write!(f, "http error: {error}"),
81	            Self::Io(error) => write!(f, "io error: {error}"),
82	            Self::Json(error) => write!(f, "json error: {error}"),
83	            Self::Api {
84	                status,
85	                error_type,
86	                message,
87	                body,
88	                ..
89	            } => match (error_type, message) {
90	                (Some(error_type), Some(message)) => {
91	                    write!(f, "api returned {status} ({error_type}): {message}")
92	                }
93	                _ => write!(f, "api returned {status}: {body}"),
94	            },
95	            Self::RetriesExhausted {
96	                attempts,
97	                last_error,
98	            } => write!(f, "api failed after {attempts} attempts: {last_error}"),
99	            Self::InvalidSseFrame(message) => write!(f, "invalid sse frame: {message}"),
100	            Self::BackoffOverflow {
101	                attempt,
102	                base_delay,
103	            } => write!(
104	                f,
105	                "retry backoff overflowed on attempt {attempt} with base delay {base_delay:?}"
106	            ),
107	        }
108	    }
109	}
