158	    async fn send_with_retry(
159	        &self,
160	        request: &MessageRequest,
161	    ) -> Result<reqwest::Response, ApiError> {
162	        let mut attempts = 0;
163	
164	        let last_error = loop {
165	            attempts += 1;
166	            let retryable_error = match self.send_raw_request(request).await {
167	                Ok(response) => match expect_success(response).await {
168	                    Ok(response) => return Ok(response),
169	                    Err(error) if error.is_retryable() && attempts <= self.max_retries + 1 => error,
170	                    Err(error) => return Err(error),
171	                },
172	                Err(error) if error.is_retryable() && attempts <= self.max_retries + 1 => error,
173	                Err(error) => return Err(error),
174	            };
175	
176	            if attempts > self.max_retries {
177	                break retryable_error;
178	            }
179	
180	            tokio::time::sleep(self.backoff_for_attempt(attempts)?).await;
181	        };
182	
183	        Err(ApiError::RetriesExhausted {
184	            attempts,
185	            last_error: Box::new(last_error),
186	        })
187	    }
188	
189	    async fn send_raw_request(
190	        &self,
191	        request: &MessageRequest,
192	    ) -> Result<reqwest::Response, ApiError> {
193	        let request_url = chat_completions_endpoint(&self.base_url);
194	        self.http
195	            .post(&request_url)
196	            .header("content-type", "application/json")
197	            .bearer_auth(&self.api_key)
198	            .json(&build_chat_completion_request(request, self.config()))
199	            .send()
200	            .await
201	            .map_err(ApiError::from)
202	    }
203	
204	    fn backoff_for_attempt(&self, attempt: u32) -> Result<Duration, ApiError> {
205	        let Some(multiplier) = 1_u32.checked_shl(attempt.saturating_sub(1)) else {
206	            return Err(ApiError::BackoffOverflow {
207	                attempt,
208	                base_delay: self.initial_backoff,
209	            });
210	        };
211	        Ok(self
212	            .initial_backoff
213	            .checked_mul(multiplier)
214	            .map_or(self.max_backoff, |delay| delay.min(self.max_backoff)))
215	    }
216	}
