397	    async fn send_with_retry(
398	        &self,
399	        request: &MessageRequest,
400	    ) -> Result<reqwest::Response, ApiError> {
401	        let mut attempts = 0;
402	        let mut last_error: Option<ApiError>;
403	
404	        loop {
405	            attempts += 1;
406	            if let Some(session_tracer) = &self.session_tracer {
407	                session_tracer.record_http_request_started(
408	                    attempts,
409	                    "POST",
410	                    "/v1/messages",
411	                    Map::new(),
412	                );
413	            }
414	            match self.send_raw_request(request).await {
415	                Ok(response) => match expect_success(response).await {
416	                    Ok(response) => {
417	                        if let Some(session_tracer) = &self.session_tracer {
418	                            session_tracer.record_http_request_succeeded(
419	                                attempts,
420	                                "POST",
421	                                "/v1/messages",
422	                                response.status().as_u16(),
423	                                request_id_from_headers(response.headers()),
424	                                Map::new(),
425	                            );
426	                        }
427	                        return Ok(response);
428	                    }
429	                    Err(error) if error.is_retryable() && attempts <= self.max_retries + 1 => {
430	                        self.record_request_failure(attempts, &error);
431	                        last_error = Some(error);
432	                    }
433	                    Err(error) => {
434	                        self.record_request_failure(attempts, &error);
435	                        return Err(error);
436	                    }
437	                },
438	                Err(error) if error.is_retryable() && attempts <= self.max_retries + 1 => {
439	                    self.record_request_failure(attempts, &error);
440	                    last_error = Some(error);
441	                }
442	                Err(error) => {
443	                    self.record_request_failure(attempts, &error);
444	                    return Err(error);
445	                }
446	            }
447	
448	            if attempts > self.max_retries {
449	                break;
450	            }
451	
452	            tokio::time::sleep(self.backoff_for_attempt(attempts)?).await;
453	        }
454	
455	        Err(ApiError::RetriesExhausted {
456	            attempts,
457	            last_error: Box::new(last_error.expect("retry loop must capture an error")),
458	        })
459	    }
