252	    pub async fn next_event(&mut self) -> Result<Option<StreamEvent>, ApiError> {
253	        loop {
254	            if let Some(event) = self.pending.pop_front() {
255	                return Ok(Some(event));
256	            }
257	
258	            if self.done {
259	                self.pending.extend(self.state.finish()?);
260	                if let Some(event) = self.pending.pop_front() {
261	                    return Ok(Some(event));
262	                }
263	                return Ok(None);
264	            }
265	
266	            match self.response.chunk().await? {
267	                Some(chunk) => {
268	                    for parsed in self.parser.push(&chunk)? {
269	                        self.pending.extend(self.state.ingest_chunk(parsed)?);
270	                    }
271	                }
272	                None => {
273	                    self.done = true;
274	                }
275	            }
276	        }
277	    }
278	}
