306	struct StreamState {
307	    model: String,
308	    message_started: bool,
309	    text_started: bool,
310	    text_finished: bool,
311	    finished: bool,
312	    stop_reason: Option<String>,
313	    usage: Option<Usage>,
314	    tool_calls: BTreeMap<u32, ToolCallState>,
315	}
316	
317	impl StreamState {
318	    fn new(model: String) -> Self {
319	        Self {
320	            model,
321	            message_started: false,
322	            text_started: false,
323	            text_finished: false,
324	            finished: false,
325	            stop_reason: None,
326	            usage: None,
327	            tool_calls: BTreeMap::new(),
328	        }
329	    }
330	
331	    fn ingest_chunk(&mut self, chunk: ChatCompletionChunk) -> Result<Vec<StreamEvent>, ApiError> {
332	        let mut events = Vec::new();
333	        if !self.message_started {
334	            self.message_started = true;
335	            events.push(StreamEvent::MessageStart(MessageStartEvent {
336	                message: MessageResponse {
337	                    id: chunk.id.clone(),
338	                    kind: "message".to_string(),
339	                    role: "assistant".to_string(),
340	                    content: Vec::new(),
341	                    model: chunk.model.clone().unwrap_or_else(|| self.model.clone()),
342	                    stop_reason: None,
343	                    stop_sequence: None,
344	                    usage: Usage {
345	                        input_tokens: 0,
346	                        cache_creation_input_tokens: 0,
347	                        cache_read_input_tokens: 0,
348	                        output_tokens: 0,
349	                    },
350	                    request_id: None,
351	                },
352	            }));
353	        }
354	
355	        if let Some(usage) = chunk.usage {
356	            self.usage = Some(Usage {
357	                input_tokens: usage.prompt_tokens,
358	                cache_creation_input_tokens: 0,
359	                cache_read_input_tokens: 0,
360	                output_tokens: usage.completion_tokens,
361	            });
362	        }
363	
364	        for choice in chunk.choices {
365	            if let Some(content) = choice.delta.content.filter(|value| !value.is_empty()) {
366	                if !self.text_started {
367	                    self.text_started = true;
368	                    events.push(StreamEvent::ContentBlockStart(ContentBlockStartEvent {
369	                        index: 0,
370	                        content_block: OutputContentBlock::Text {
371	                            text: String::new(),
372	                        },
373	                    }));
374	                }
375	                events.push(StreamEvent::ContentBlockDelta(ContentBlockDeltaEvent {
376	                    index: 0,
377	                    delta: ContentBlockDelta::TextDelta { text: content },
378	                }));
379	            }
380	
381	            for tool_call in choice.delta.tool_calls {
382	                let state = self.tool_calls.entry(tool_call.index).or_default();
383	                state.apply(tool_call);
384	                let block_index = state.block_index();
385	                if !state.started {
386	                    if let Some(start_event) = state.start_event()? {
387	                        state.started = true;
388	                        events.push(StreamEvent::ContentBlockStart(start_event));
389	                    } else {
390	                        continue;
391	                    }
392	                }
393	                if let Some(delta_event) = state.delta_event() {
394	                    events.push(StreamEvent::ContentBlockDelta(delta_event));
395	                }
396	                if choice.finish_reason.as_deref() == Some("tool_calls") && !state.stopped {
397	                    state.stopped = true;
398	                    events.push(StreamEvent::ContentBlockStop(ContentBlockStopEvent {
399	                        index: block_index,
400	                    }));
401	                }
402	            }
403	
404	            if let Some(finish_reason) = choice.finish_reason {
405	                self.stop_reason = Some(normalize_finish_reason(&finish_reason));
406	                if finish_reason == "tool_calls" {
407	                    for state in self.tool_calls.values_mut() {
408	                        if state.started && !state.stopped {
409	                            state.stopped = true;
410	                            events.push(StreamEvent::ContentBlockStop(ContentBlockStopEvent {
411	                                index: state.block_index(),
412	                            }));
413	                        }
414	                    }
415	                }
416	            }
417	        }
418	
419	        Ok(events)
420	    }
421	
422	    fn finish(&mut self) -> Result<Vec<StreamEvent>, ApiError> {
423	        if self.finished {
424	            return Ok(Vec::new());
425	        }
426	        self.finished = true;
427	
428	        let mut events = Vec::new();
429	        if self.text_started && !self.text_finished {
430	            self.text_finished = true;
431	            events.push(StreamEvent::ContentBlockStop(ContentBlockStopEvent {
432	                index: 0,
433	            }));
434	        }
435	
436	        for state in self.tool_calls.values_mut() {
437	            if !state.started {
438	                if let Some(start_event) = state.start_event()? {
439	                    state.started = true;
440	                    events.push(StreamEvent::ContentBlockStart(start_event));
441	                    if let Some(delta_event) = state.delta_event() {
442	                        events.push(StreamEvent::ContentBlockDelta(delta_event));
443	                    }
444	                }
445	            }
446	            if state.started && !state.stopped {
447	                state.stopped = true;
448	                events.push(StreamEvent::ContentBlockStop(ContentBlockStopEvent {
449	                    index: state.block_index(),
450	                }));
451	            }
452	        }
453	
454	        if self.message_started {
455	            events.push(StreamEvent::MessageDelta(MessageDeltaEvent {
456	                delta: MessageDelta {
457	                    stop_reason: Some(
458	                        self.stop_reason
459	                            .clone()
460	                            .unwrap_or_else(|| "end_turn".to_string()),
461	                    ),
462	                    stop_sequence: None,
463	                },
464	                usage: self.usage.clone().unwrap_or(Usage {
465	                    input_tokens: 0,
466	                    cache_creation_input_tokens: 0,
467	                    cache_read_input_tokens: 0,
468	                    output_tokens: 0,
469	                }),
470	            }));
471	            events.push(StreamEvent::MessageStop(MessageStopEvent {}));
472	        }
473	        Ok(events)
474	    }
475	}
