593	pub fn resolve_startup_auth_source<F>(load_oauth_config: F) -> Result<AuthSource, ApiError>
594	where
595	    F: FnOnce() -> Result<Option<OAuthConfig>, ApiError>,
596	{
597	    if let Some(api_key) = read_env_non_empty("ANTHROPIC_API_KEY")? {
598	        return match read_env_non_empty("ANTHROPIC_AUTH_TOKEN")? {
599	            Some(bearer_token) => Ok(AuthSource::ApiKeyAndBearer {
600	                api_key,
601	                bearer_token,
602	            }),
603	            None => Ok(AuthSource::ApiKey(api_key)),
604	        };
605	    }
606	    if let Some(bearer_token) = read_env_non_empty("ANTHROPIC_AUTH_TOKEN")? {
607	        return Ok(AuthSource::BearerToken(bearer_token));
608	    }
609	
610	    let Some(token_set) = load_saved_oauth_token()? else {
611	        return Err(ApiError::missing_credentials(
612	            "Anthropic",
613	            &["ANTHROPIC_AUTH_TOKEN", "ANTHROPIC_API_KEY"],
614	        ));
615	    };
616	    if !oauth_token_is_expired(&token_set) {
617	        return Ok(AuthSource::BearerToken(token_set.access_token));
618	    }
619	    if token_set.refresh_token.is_none() {
620	        return Err(ApiError::ExpiredOAuthToken);
621	    }
622	
623	    let Some(config) = load_oauth_config()? else {
624	        return Err(ApiError::Auth(
625	            "saved OAuth token is expired; runtime OAuth config is missing".to_string(),
626	        ));
627	    };
628	    Ok(AuthSource::from(resolve_saved_oauth_token_set(
629	        &config, token_set,
630	    )?))
631	}
