633	fn resolve_saved_oauth_token_set(
634	    config: &OAuthConfig,
635	    token_set: OAuthTokenSet,
636	) -> Result<OAuthTokenSet, ApiError> {
637	    if !oauth_token_is_expired(&token_set) {
638	        return Ok(token_set);
639	    }
640	    let Some(refresh_token) = token_set.refresh_token.clone() else {
641	        return Err(ApiError::ExpiredOAuthToken);
642	    };
643	    let client = AnthropicClient::from_auth(AuthSource::None).with_base_url(read_base_url());
644	    let refreshed = client_runtime_block_on(async {
645	        client
646	            .refresh_oauth_token(
647	                config,
648	                &OAuthRefreshRequest::from_config(
649	                    config,
650	                    refresh_token,
651	                    Some(token_set.scopes.clone()),
652	                ),
653	            )
654	            .await
655	    })?;
656	    let resolved = OAuthTokenSet {
657	        access_token: refreshed.access_token,
658	        refresh_token: refreshed.refresh_token.or(token_set.refresh_token),
659	        expires_at: refreshed.expires_at,
660	        scopes: refreshed.scopes,
661	    };
662	    save_oauth_credentials(&runtime::OAuthTokenSet {
663	        access_token: resolved.access_token.clone(),
664	        refresh_token: resolved.refresh_token.clone(),
665	        expires_at: resolved.expires_at,
666	        scopes: resolved.scopes.clone(),
667	    })
668	    .map_err(ApiError::from)?;
669	    Ok(resolved)
670	}
